mapper.select:
SELECT c.category_id as ID, c.category_name as name, c.slug as slug, c.image_url as image_url, c.banner_image_url as banner_image_url, c.active as active, c.featured as featured, c.level as level, c.product_count as product_count FROM hm_query.dim_category c
AND c.banner_image_url IS NOT NULL AND c.active = #{active} AND c.category_name ILIKE CONCAT('%', #{name}, '%') AND (c.category_name ILIKE CONCAT('%', #{q}, '%') OR c.slug ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT c.category_id as ID, c.category_name as name, c.slug as slug, c.parent_id as parent_id, c.level as level, c.image_url as image_url, c.icon as icon, c.display_order as display_order FROM hm_query.dim_category c
AND c.active = true AND c.show_in_menu = true AND c.parent_id = #{parentId} AND c.level = #{level} AND c.category_name ILIKE CONCAT('%', #{name}, '%') AND (c.category_name ILIKE CONCAT('%', #{q}, '%') OR c.slug ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.dim_category

    AND active = true
    AND parent_id = #{parentId}
    AND level = #{level}
    AND category_name ILIKE CONCAT('%', #{name}, '%')
    AND (category_name ILIKE CONCAT('%', #{q}, '%') OR slug ILIKE CONCAT('%', #{q}, '%'))

SELECT c.category_id as ID, c.category_name as name, c.slug as slug, c.parent_id as parent_id, c.level as level, c.image_url as image_url, c.icon as icon, c.display_order as display_order FROM hm_query.dim_category c
AND c.active = true AND c.parent_id = #{parentId} AND c.level = #{level} AND c.category_name ILIKE CONCAT('%', #{name}, '%') AND (c.category_name ILIKE CONCAT('%', #{q}, '%') OR c.slug ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.dim_category

    AND active = #{active}
    AND (parent_id = #{parentId} OR (#{parentId} = '' AND (parent_id IS NULL OR parent_id = '')))
    AND level = #{level}
    AND category_name ILIKE '%' || #{name} || '%'
    AND (category_name ILIKE CONCAT('%', #{q}, '%') OR slug ILIKE CONCAT('%', #{q}, '%'))

SELECT c.category_id as id, c.category_name as name, c.slug, c.description, c.parent_id, c.level, c.display_order, c.active, c.featured, c.image_url, c.icon, c.show_in_menu, EXISTS (SELECT 1 FROM hm_query.dim_category ch WHERE ch.parent_id = c.category_id) AS has_children FROM hm_query.dim_category c
AND c.active = #{active} AND (c.parent_id = #{parentId} OR (#{parentId} = '' AND (c.parent_id IS NULL OR c.parent_id = ''))) AND c.level = #{level} AND c.category_name ILIKE '%' || #{name} || '%' AND (c.category_name ILIKE CONCAT('%', #{q}, '%') OR c.slug ILIKE CONCAT('%', #{q}, '%'))
ORDER BY c.level ASC, c.display_order ASC ${pagination}

SELECT COUNT(*) FROM hm_query.category_config_flat

    AND category_id = #{categoryId}
    AND CASE WHEN is_gated THEN 'GATED' ELSE 'OPEN' END = #{restrictionType}
    AND (name ILIKE CONCAT('%', #{q}, '%') OR hsn_code ILIKE CONCAT('%', #{q}, '%'))

SELECT ccf.id, ccf.category_id, ccf.name as category_name, ccf.depth as category_level, ccf.commission_rate_bps as commission_rate, ccf.gst_rate_pct as gst_rate, ccf.hsn_code, ccf.return_policy_days as return_days, '' as return_type, ccf.max_shipping_weight_grams / 1000 as max_weight_kg, '' as shipping_type, CASE WHEN ccf.is_gated THEN 'GATED' ELSE 'OPEN' END as restriction_type, '' as required_license, ccf.listing_min_images as min_images, ccf.listing_min_desc_length as min_description_length, false as ean_required FROM hm_query.category_config_flat ccf
AND ccf.category_id = #{categoryId} AND CASE WHEN ccf.is_gated THEN 'GATED' ELSE 'OPEN' END = #{restrictionType} AND (ccf.name ILIKE CONCAT('%', #{q}, '%') OR ccf.hsn_code ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.category_config_flat

    AND depth = #{level}
    AND active = #{active}
    AND name ILIKE CONCAT('%', #{q}, '%')

SELECT
    ccf.category_id, ccf.name as category_name, ccf.active,
    ccf.product_count as product_count,
    ccf.seller_count as seller_count
FROM hm_query.category_config_flat ccf

    AND ccf.depth = #{level}
    AND ccf.active = #{active}
    AND ccf.name ILIKE CONCAT('%', #{q}, '%')

${orderby} ${pagination}

SELECT adf.attribute_id as id, '' as category_id, '' as category_name, adf.label as attribute_name, adf.input_type as attribute_type, adf.required as is_required, adf.options_json as allowed_values, adf.display_order as sort_order FROM hm_query.attribute_definition_flat adf
AND adf.category_count > 0 AND adf.required = #{isRequired} AND adf.label ILIKE CONCAT('%', #{q}, '%')
${orderby} ${pagination}
